"use client";

import * as React from "react";
import { type MotionValue, useMotionValue, useMotionValueEvent } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { clamp01, damp, usePrefersReducedMotion } from "@/components/experience/experience-runtime";
import { useElementScrollProgress } from "@/components/experience/use-element-scroll-progress";
import { useWebGLStage } from "@/components/experience/use-webgl-stage";

export type ParticleAssemblyProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  src: string;
  colorSrc?: string;
  alt: string;
  trigger?: "scroll" | "hover" | "controlled";
  progress?: MotionValue<number>;
  particleCount?: number;
  pointSize?: number;
  color?: THREE.ColorRepresentation;
  sourceColorMix?: number;
  /** Multiplies the final particle color; lifts dark product sources above the additive floor. */
  colorBoost?: number;
  /** Depth amplitude derived from source luminance (color source when present, else the matte). */
  relief?: number;
  sampling?: "auto" | "alpha" | "light" | "dark";
  scatter?: number;
  scrollScreens?: number;
  smoothing?: number;
  invert?: boolean;
  children?: React.ReactNode;
  fallback?: React.ReactNode;
  maxDpr?: number;
  stageClassName?: string;
};

const VERTEX = /* glsl */ `
  attribute vec3 aTarget;
  attribute vec3 aScatter;
  attribute float aSeed;
  attribute vec3 aColor;
  uniform float uProgress;
  uniform float uPointSize;
  uniform float uTime;
  varying float vAlpha;
  varying vec3 vColor;
  void main() {
    float eased = uProgress * uProgress * (3. - 2. * uProgress);
    float wave = sin(aSeed * 23. + uTime * .45) * .035 * (1. - eased);
    vec3 p = mix(aScatter, aTarget, eased);
    p.z += wave;
    vec4 mv = modelViewMatrix * vec4(p, 1.);
    gl_Position = projectionMatrix * mv;
    gl_PointSize = uPointSize * (1. + eased * .5) * (5. / max(1., -mv.z));
    vAlpha = .22 + eased * .78;
    vColor = aColor;
  }
`;

const FRAGMENT = /* glsl */ `
  precision highp float;
  uniform vec3 uColor;
  uniform float uColorMix;
  uniform float uColorBoost;
  varying float vAlpha;
  varying vec3 vColor;
  void main() {
    float d = length(gl_PointCoord - .5);
    float alpha = (1. - smoothstep(.22, .5, d)) * vAlpha;
    gl_FragColor = vec4(mix(uColor, vColor, uColorMix) * uColorBoost, alpha);
  }
`;

/** Morphs a transparent or high-contrast source into a point cloud target. */
export function ParticleAssembly({
  alt,
  children,
  className,
  color = "#d9ff62",
  colorBoost = 1,
  colorSrc,
  fallback,
  invert = false,
  label,
  maxDpr = 1.6,
  particleCount = 6200,
  pointSize = 7,
  progress: controlledProgress,
  relief = 0.12,
  scatter = 3.8,
  sampling = "auto",
  scrollScreens = 2.8,
  smoothing = 7,
  sourceColorMix = 0.82,
  src,
  stageClassName,
  trigger = "scroll",
  onPointerEnter,
  onPointerLeave,
  ...props
}: ParticleAssemblyProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const stageRef = React.useRef<HTMLDivElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const desiredRef = React.useRef(0);
  const actualRef = React.useRef(0);
  const localProgress = useElementScrollProgress(rootRef);
  const fallbackProgress = useMotionValue(0);
  const progress = controlledProgress ?? (trigger === "scroll" ? localProgress : fallbackProgress);
  const progressRef = React.useRef(progress);
  React.useInsertionEffect(() => {
    progressRef.current = progress;
  });
  const staticMode = usePrefersReducedMotion();
  useMotionValueEvent(progress, "change", (value) => {
    desiredRef.current = invert ? 1 - clamp01(value) : clamp01(value);
  });
  // Re-derive the desired progress whenever the interaction contract changes,
  // so a late `invert` or `trigger` switch cannot leave a stale target behind.
  React.useEffect(() => {
    const value = trigger === "hover" ? 0 : clamp01(progressRef.current.get());
    desiredRef.current = invert ? 1 - value : value;
  }, [invert, trigger]);

  const { ready, failed } = useWebGLStage({
    stageRef,
    canvasRef,
    enabled: !staticMode,
    maxDpr,
    alpha: true,
    // `trigger` swaps the stage DOM (and therefore the canvas element), so the
    // scene must rebuild against the freshly mounted canvas.
    signature: JSON.stringify([color, colorBoost, colorSrc, particleCount, pointSize, relief, sampling, scatter, smoothing, sourceColorMix, src, trigger]),
    create: ({ renderer, markReady, markFailed, isDisposed }) => {
      let elapsed = 0;
      const scene = new THREE.Scene();
      const camera = new THREE.PerspectiveCamera(34, 1, 0.1, 100);
      camera.position.z = 6;
      const geometry = new THREE.BufferGeometry();
      const uniforms = {
        uProgress: { value: 0 },
        uPointSize: { value: pointSize },
        uTime: { value: 0 },
        uColor: { value: new THREE.Color(color) },
        uColorMix: { value: colorSrc ? Math.max(0, Math.min(1, sourceColorMix)) : 0 },
        uColorBoost: { value: Math.max(0, colorBoost) },
      };
      const material = new THREE.ShaderMaterial({ vertexShader: VERTEX, fragmentShader: FRAGMENT, uniforms, transparent: true, depthWrite: false, blending: THREE.AdditiveBlending });
      const points = new THREE.Points(geometry, material);
      scene.add(points);

      const load = async () => {
        try {
          const loadImage = async (source: string) => {
            const image = new Image();
            image.decoding = "async";
            image.src = source;
            await image.decode();
            return image;
          };
          const [image, colorImage] = await Promise.all([loadImage(src), colorSrc ? loadImage(colorSrc) : Promise.resolve(null)]);
          if (isDisposed()) return;
          const sampleSize = 256;
          const sampleCanvas = document.createElement("canvas");
          sampleCanvas.width = sampleSize;
          sampleCanvas.height = sampleSize;
          const context = sampleCanvas.getContext("2d", { willReadFrequently: true });
          if (!context) throw new Error("Canvas 2D unavailable");
          const ratio = Math.min(sampleSize / image.naturalWidth, sampleSize / image.naturalHeight);
          const width = image.naturalWidth * ratio;
          const height = image.naturalHeight * ratio;
          context.clearRect(0, 0, sampleSize, sampleSize);
          context.drawImage(image, (sampleSize - width) / 2, (sampleSize - height) / 2, width, height);
          const pixels = context.getImageData(0, 0, sampleSize, sampleSize).data;
          let colorPixels: Uint8ClampedArray | null = null;
          if (colorImage) {
            const colorCanvas = document.createElement("canvas");
            colorCanvas.width = sampleSize;
            colorCanvas.height = sampleSize;
            const colorContext = colorCanvas.getContext("2d", { willReadFrequently: true });
            if (colorContext) {
              const colorRatio = Math.min(sampleSize / colorImage.naturalWidth, sampleSize / colorImage.naturalHeight);
              const colorWidth = colorImage.naturalWidth * colorRatio;
              const colorHeight = colorImage.naturalHeight * colorRatio;
              colorContext.drawImage(colorImage, (sampleSize - colorWidth) / 2, (sampleSize - colorHeight) / 2, colorWidth, colorHeight);
              colorPixels = colorContext.getImageData(0, 0, sampleSize, sampleSize).data;
            }
          }
          const hasTransparency = pixels.some((value, index) => index % 4 === 3 && value < 240);
          const resolvedSampling = sampling === "auto" ? (hasTransparency ? "alpha" : "dark") : sampling;
          const candidates: Array<[number, number, number, number, number, number]> = [];
          for (let y = 0; y < sampleSize; y += 1) {
            for (let x = 0; x < sampleSize; x += 1) {
              const index = (y * sampleSize + x) * 4;
              const alpha = pixels[index + 3]! / 255;
              const luminance = (pixels[index]! + pixels[index + 1]! + pixels[index + 2]!) / 765;
              const selected = resolvedSampling === "alpha" ? alpha > 0.12 : resolvedSampling === "light" ? luminance > 0.52 : luminance < 0.48;
              if (selected) {
                const source = colorPixels ?? pixels;
                const sourceLuminance = (source[index]! + source[index + 1]! + source[index + 2]!) / 765;
                candidates.push([
                  (x / sampleSize - 0.5) * 4.15,
                  (0.5 - y / sampleSize) * 4.15,
                  (sourceLuminance - 0.5) * relief,
                  source[index]! / 255,
                  source[index + 1]! / 255,
                  source[index + 2]! / 255,
                ]);
              }
            }
          }
          if (!candidates.length) throw new Error("No target pixels");
          const count = Math.min(Math.max(600, particleCount), 32000);
          const target = new Float32Array(count * 3);
          const scattered = new Float32Array(count * 3);
          const seeds = new Float32Array(count);
          const sourceColors = new Float32Array(count * 3);
          for (let index = 0; index < count; index += 1) {
            const candidate = candidates[Math.floor(Math.random() * candidates.length)]!;
            const offset = index * 3;
            target[offset] = candidate[0] + (Math.random() - 0.5) * 0.025;
            target[offset + 1] = candidate[1] + (Math.random() - 0.5) * 0.025;
            target[offset + 2] = candidate[2];
            sourceColors[offset] = candidate[3];
            sourceColors[offset + 1] = candidate[4];
            sourceColors[offset + 2] = candidate[5];
            const theta = Math.random() * Math.PI * 2;
            const radius = scatter * (0.3 + Math.pow(Math.random(), 0.55));
            scattered[offset] = Math.cos(theta) * radius;
            scattered[offset + 1] = Math.sin(theta) * radius * 0.72;
            scattered[offset + 2] = (Math.random() - 0.5) * scatter * 1.4;
            seeds[index] = Math.random();
          }
          geometry.setAttribute("position", new THREE.BufferAttribute(target, 3));
          geometry.setAttribute("aTarget", new THREE.BufferAttribute(target, 3));
          geometry.setAttribute("aScatter", new THREE.BufferAttribute(scattered, 3));
          geometry.setAttribute("aSeed", new THREE.BufferAttribute(seeds, 1));
          geometry.setAttribute("aColor", new THREE.BufferAttribute(sourceColors, 3));
          markReady();
        } catch {
          markFailed();
        }
      };
      void load();

      return {
        onResize: (width, height) => {
          camera.aspect = width / height;
          camera.updateProjectionMatrix();
          const mobileScale = width < 640 ? 0.74 : 1;
          points.scale.setScalar(mobileScale);
        },
        onFrame: (delta) => {
          elapsed += delta;
          actualRef.current = damp(actualRef.current, desiredRef.current, smoothing, delta);
          uniforms.uProgress.value = actualRef.current;
          uniforms.uTime.value = elapsed;
          points.rotation.y = (1 - actualRef.current) * 0.18;
          renderer.render(scene, camera);
        },
        dispose: () => {
          geometry.dispose();
          material.dispose();
        },
      };
    },
  });

  const handlePointerEnter = (event: React.PointerEvent<HTMLElement>) => {
    if (trigger === "hover") desiredRef.current = invert ? 0 : 1;
    onPointerEnter?.(event);
  };
  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => {
    if (trigger === "hover") desiredRef.current = invert ? 1 : 0;
    onPointerLeave?.(event);
  };
  const posterStyle = { backgroundImage: `url("${src.replaceAll('"', '%22')}")` };
  const content = (
    <div ref={stageRef} className={cn("sticky top-0 h-svh overflow-hidden", stageClassName)}>
      <span className="sr-only">{alt}</span>
      <div aria-hidden className={cn("absolute inset-0 bg-contain bg-center bg-no-repeat transition-opacity duration-500", (failed || staticMode) ? "opacity-100" : "opacity-0")} style={posterStyle} />
      <canvas ref={canvasRef} aria-hidden className={cn("absolute inset-0 size-full transition-opacity duration-500", ready && !failed && !staticMode ? "opacity-100" : "opacity-0")} />
      {(failed || staticMode) && fallback ? <div className="absolute inset-0">{fallback}</div> : null}
      <div className="relative h-full">{children}</div>
    </div>
  );

  return (
    <section ref={rootRef} aria-label={label} data-particle-assembly data-trigger={trigger} data-ready={ready || undefined} className={cn("relative", className)} style={trigger === "scroll" ? { minHeight: `${Math.max(1, scrollScreens) * 100}svh` } : undefined} onPointerEnter={handlePointerEnter} onPointerLeave={handlePointerLeave} {...props}>
      {trigger === "scroll" ? content : <div className="h-svh">{React.cloneElement(content, { className: cn("relative h-full", stageClassName) })}</div>}
    </section>
  );
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}

"use client";

import * as React from "react";
import { useMotionValue } from "motion/react";

/**
 * Stable `start start` → `end end` progress for pinned sections. It measures
 * the section itself, so progress remains monotonic all the way to the final
 * pixel and does not wrap when a sticky child releases.
 */
export function useElementScrollProgress(
  target: React.RefObject<HTMLElement | null>,
) {
  const progress = useMotionValue(0);

  React.useEffect(() => {
    const element = target.current;
    if (!element) return;
    let frame = 0;
    const measure = () => {
      const rect = element.getBoundingClientRect();
      const travel = Math.max(1, element.offsetHeight - window.innerHeight);
      progress.set(Math.max(0, Math.min(1, -rect.top / travel)));
    };
    const update = () => {
      cancelAnimationFrame(frame);
      frame = requestAnimationFrame(measure);
    };
    const resizeObserver = new ResizeObserver(update);
    resizeObserver.observe(element);
    window.addEventListener("scroll", update, { passive: true });
    window.addEventListener("resize", update, { passive: true });
    // Synchronous first measurement: consumers that render a bootstrap frame
    // before the first animation frame (e.g. a restored scroll position in a
    // background tab) already see the true progress.
    measure();
    return () => {
      cancelAnimationFrame(frame);
      resizeObserver.disconnect();
      window.removeEventListener("scroll", update);
      window.removeEventListener("resize", update);
    };
  }, [progress, target]);

  return progress;
}

"use client";

import * as React from "react";
import * as THREE from "three";

import { supportsWebGL } from "@/components/experience/experience-runtime";

export type WebGLStageContext = {
  renderer: THREE.WebGLRenderer;
  stage: HTMLElement;
  canvas: HTMLCanvasElement;
  /** Flip the stage to ready once async assets are decoded and the first frame can show. */
  markReady: () => void;
  /** Flip the stage to failed (poster/fallback becomes visible). */
  markFailed: () => void;
  /** True after the stage effect has been cleaned up; guard async callbacks with it. */
  isDisposed: () => boolean;
  /** Re-run the resize pass — call after async assets load so size-dependent caps apply. */
  requestResize: () => void;
};

export type WebGLStageHandle = {
  /** Runs every animation frame while the stage is on screen, the tab is visible and the context is alive. */
  onFrame?: (deltaSeconds: number, time: number) => void;
  /** Runs after the renderer resized; update cameras, uniforms and derived scales here. */
  onResize?: (width: number, height: number) => void;
  /** Optional extra cap on device pixel ratio for a given stage size (e.g. never supersample past the source texture). */
  getDpr?: (width: number, height: number) => number;
  /** Dispose geometries, materials and textures created in `create`; the renderer itself is disposed by the hook. */
  dispose?: () => void;
};

export type WebGLStageOptions = {
  stageRef: React.RefObject<HTMLElement | null>;
  canvasRef: React.RefObject<HTMLCanvasElement | null>;
  /** false keeps the stage fully inert — use it for reduced-motion / coarse-pointer static modes. */
  enabled: boolean;
  maxDpr?: number;
  antialias?: boolean;
  alpha?: boolean;
  /** Request a stencil buffer (three defaults it off since r163); needed for aperture/mask scenes. */
  stencil?: boolean;
  /**
   * Serialize every visual prop that must rebuild the scene into this string.
   * Array or callback identity never triggers a rebuild, so inline props stay safe.
   */
  signature?: string;
  /** Root margin for the offscreen pause observer. */
  rootMargin?: string;
  /** Build the scene. Reads props freely (latest values are visible via closure on each rebuild). */
  create: (context: WebGLStageContext) => WebGLStageHandle | void;
};

/**
 * Shared WebGL lifecycle for experience stages: renderer with capped DPR,
 * resize + offscreen observers, a visibility-gated animation loop, context-loss
 * pause with context-restore recovery, and full disposal. Components own only
 * their scene graph and per-frame logic.
 */
export function useWebGLStage({
  alpha = false,
  antialias = false,
  canvasRef,
  create,
  enabled,
  maxDpr = 1.6,
  rootMargin = "20% 0px",
  signature,
  stageRef,
  stencil = false,
}: WebGLStageOptions) {
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const createRef = React.useRef(create);
  React.useInsertionEffect(() => {
    createRef.current = create;
  });

  React.useEffect(() => {
    const stage = stageRef.current;
    const canvas = canvasRef.current;
    if (!stage || !canvas || !enabled) return;
    if (!supportsWebGL()) {
      const timer = window.setTimeout(() => setFailed(true), 0);
      return () => window.clearTimeout(timer);
    }

    let disposed = false;
    let frame = 0;
    let previous = performance.now();
    let contextAlive = true;
    let lossTimer = 0;
    let onScreen = true;

    const renderer = new THREE.WebGLRenderer({ canvas, antialias, alpha, stencil, powerPreference: "high-performance" });
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, maxDpr));

    let handle: WebGLStageHandle = {};
    const resize = () => {
      const width = Math.max(1, stage.clientWidth);
      const height = Math.max(1, stage.clientHeight);
      const extraCap = handle.getDpr?.(width, height) ?? Number.POSITIVE_INFINITY;
      renderer.setPixelRatio(Math.max(0.5, Math.min(window.devicePixelRatio || 1, maxDpr, extraCap)));
      renderer.setSize(width, height, false);
      handle.onResize?.(width, height);
    };
    const context: WebGLStageContext = {
      renderer,
      stage,
      canvas,
      markReady: () => {
        if (!disposed) setReady(true);
      },
      markFailed: () => {
        if (!disposed) setFailed(true);
      },
      isDisposed: () => disposed,
      requestResize: () => {
        if (!disposed) resize();
      },
    };
    handle = createRef.current(context) ?? {};
    const resizeObserver = new ResizeObserver(resize);
    resizeObserver.observe(stage);

    const intersectionObserver = new IntersectionObserver(
      ([entry]) => {
        onScreen = Boolean(entry?.isIntersecting);
      },
      { rootMargin },
    );
    intersectionObserver.observe(stage);

    // preventDefault opts into restoration; Three re-uploads retained resources
    // on the next render after the context returns. Only a loss that never
    // restores becomes a visible failure.
    const contextLost = (event: Event) => {
      event.preventDefault();
      contextAlive = false;
      window.clearTimeout(lossTimer);
      lossTimer = window.setTimeout(() => {
        if (!disposed && !contextAlive) setFailed(true);
      }, 2500);
    };
    const contextRestored = () => {
      window.clearTimeout(lossTimer);
      contextAlive = true;
      if (disposed) return;
      setFailed(false);
      resize();
    };
    canvas.addEventListener("webglcontextlost", contextLost);
    canvas.addEventListener("webglcontextrestored", contextRestored);

    const render = (time: number) => {
      if (disposed) return;
      const delta = Math.min(0.05, Math.max(0.001, (time - previous) / 1000));
      previous = time;
      if (contextAlive && onScreen && document.visibilityState === "visible") {
        handle.onFrame?.(delta, time);
      }
      frame = requestAnimationFrame(render);
    };

    resize();
    frame = requestAnimationFrame(render);

    return () => {
      disposed = true;
      cancelAnimationFrame(frame);
      window.clearTimeout(lossTimer);
      resizeObserver.disconnect();
      intersectionObserver.disconnect();
      canvas.removeEventListener("webglcontextlost", contextLost);
      canvas.removeEventListener("webglcontextrestored", contextRestored);
      handle.dispose?.();
      renderer.dispose();
    };
  }, [alpha, antialias, canvasRef, enabled, maxDpr, rootMargin, signature, stageRef, stencil]);

  return { ready, failed };
}
